parameters.functionCode:
const campaigns = $input.first().json;

const kpis = {
  totalSpend: campaigns.reduce((a, c) => a + c.spend, 0),
  totalImpressions: campaigns.reduce((a, c) => a + c.impressions, 0),
  totalClicks: campaigns.reduce((a, c) => a + c.clicks, 0),
  totalConversions: campaigns.reduce((a, c) => a + c.conversions, 0),
  avgCTR: campaigns.reduce((a, c) => a + c.ctr, 0) / campaigns.length,
  avgCPA: campaigns.reduce((a, c) => a + c.cpa, 0) / campaigns.length,
  avgROAS: campaigns.reduce((a, c) => a + c.roas, 0) / campaigns.length
};

// Identify anomalies
const outliers = campaigns.filter(c => c.roas > kpis.avgROAS * 1.5 || c.roas < kpis.avgROAS * 0.5);

return { kpis, outliers, campaignCount: campaigns.length };

